            m = sy
        }

        // If we can move towards the target in x or y direction
        if sx < tx && sy < ty {
            // If both x and y are less than target, move in the direction of the larger coordinate
            if sx > sy {
                sx += m
            } else {
                sy += m
            }
        } else if sx < tx {
            // Move in x direction
            sx += m
        } else if sy < ty {
            // Move in y direction
            sy += m
        } else {
